const b = ($input.first().json.body) || {};
return [{
  json: {
    documentId: b.document_id || ('doc_' + Date.now()),
    guestId: b.guest_id || 'unknown',
    bookingId: b.booking_id || '',
    imageUrl: b.image_url || b.imageUrl || '',
    docType: b.doc_type || 'receipt',
    expectedAmount: (b.expected_amount != null) ? Number(b.expected_amount) : null,
    expectedCurrency: String(b.currency || 'EUR').toUpperCase(),
    receivedAt: new Date().toISOString()
  }
}];

const res = $input.first().json;
let content = '{}';
try { content = res.choices[0].message.content; } catch (e) {}
let parsed = {};
try { parsed = JSON.parse(content); } catch (e) { parsed = { confidence: 0 }; }
const prev = $node['Normalize Input'].json;
return [{
  json: {
    documentId: prev.documentId,
    guestId: prev.guestId,
    bookingId: prev.bookingId,
    expectedAmount: prev.expectedAmount,
    expectedCurrency: prev.expectedCurrency,
    vendor: parsed.vendor ?? null,
    date: parsed.document_date ?? null,
    total: (parsed.total != null) ? Number(parsed.total) : null,
    currency: parsed.currency ? String(parsed.currency).toUpperCase() : null,
    lineItems: parsed.line_items ?? [],
    confidence: (parsed.confidence != null) ? Number(parsed.confidence) : 0
  }
}];

const d = $input.first().json;
const reasons = [];
const tolerance = 0.02;
if (d.confidence < 0.6) reasons.push('Low extraction confidence');
if (d.total == null) reasons.push('Total not found');
if (d.currency && d.expectedCurrency && d.currency !== d.expectedCurrency) {
  reasons.push('Currency mismatch: got ' + d.currency + ' expected ' + d.expectedCurrency);
}
if (d.total != null && d.expectedAmount != null) {
  const diff = Math.abs(d.total - d.expectedAmount);
  const allowed = Math.abs(d.expectedAmount) * tolerance;
  if (diff > allowed) reasons.push('Amount mismatch: got ' + d.total + ' expected ' + d.expectedAmount);
}
let verdict = 'APPROVED';
if (reasons.length > 0) {
  verdict = (d.confidence < 0.6 || d.total == null) ? 'REJECTED' : 'REVIEW';
}
return [{
  json: Object.assign({}, d, {
    verdict: verdict,
    reasons: reasons.length ? reasons : ['All checks passed'],
    processedAt: new Date().toISOString()
  })
}];

